'use strict';

function hex(n) {
  return `#${(n & 0xffffff).toString(16).padStart(6, '0')}`;
}

function palette(num) {
  const seed = (num * 2654435761) >>> 0;
  return {
    bg: hex(0xf4f7f9 ^ (seed & 0x0f0f0f)),
    card: hex(0xe5edf2 ^ ((seed >>> 4) & 0x171717)),
    accent: hex(0x286c91 ^ ((seed >>> 8) & 0x5f5f5f)),
    text: hex(0x182734 ^ ((seed >>> 12) & 0x171717)),
  };
}

function spec(data) {
  const groups = data.num <= 220
    ? 'Specialized Medical'
    : data.num <= 240
      ? 'Heavy Industry & B2B'
      : data.num <= 260
        ? 'Retail & Lifestyle'
        : data.num <= 280
          ? 'Logistics & Rental'
          : 'Specialized Education';
  return {
    num: data.num,
    id: data.id,
    niche: data.niche,
    name: data.name,
    emoji: data.emoji,
    group: groups,
    title: data.title,
    tagline: data.tagline,
    page2: { file: data.page, label: data.label },
    usps: data.usps,
    p1: data.p1,
    p2: data.p2,
    p3: data.p3,
    keywords: data.keywords,
    colors: palette(data.num),
    imgTheme: data.img,
  };
}

